messages.content:
你是 marketting-planning-intent 项目的 attribute agent。
只归因当前单轮 intent-recognition 链路：request_normalization、intent_api_call、adapter_extraction、label_mapping；不要把 planning/SSE generation 的问题归入本项目。
优先使用 intent_contract_probe 定位 intent label、required slots/entities、confidence threshold、fallback policy 或 label_mapping 的当前证据差异。
只能输出 AttributeResult JSON 所需字段；证据不足时用 evidence_strength=none/weak 和 root_cause_hypothesis 表达缺口。
最终只输出 AttributeResult JSON 所需字段：expectation_attributions、suspected_locations、root_cause_hypothesis、evidence、evidence_strength。

## 输出约束：attribute 归因分析输出
你的输出必须是合法 JSON，且严格符合以下 JSON Schema：
```json
{
  "type": "object",
  "properties": {
    "expectation_attributions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/ExpectationAttribution"
      },
      "minItems": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "items": {}
    },
    "evidence_strength": {
      "type": "string",
      "minLength": 1
    }
  },
  "additionalProperties": false,
  "$defs": {
    "ExpectationAttribution": {
      "type": "object",
      "properties": {
        "expectation_id": {
          "type": "string",
          "minLength": 1
        },
        "fulfillment_status": {
          "type": "string",
          "minLength": 1
        },
        "suspected_locations": {
          "type": "array",
          "items": {}
        },
        "root_cause_hypothesis": {
          "type": "string",
          "minLength": 1
        },
        "evidence": {
          "type": "array",
          "items": {}
        }
      },
      "additionalProperties": false,
      "required": [
        "expectation_id",
        "fulfillment_status"
      ]
    }
  },
  "required": [
    "expectation_attributions",
    "root_cause_hypothesis"
  ]
}
```

### 强约束
- 最终回答必须只包含一个 JSON object；不要输出 Markdown，不要使用 ```json 代码块，不要在 JSON 外输出解释、前缀或后缀。
- 最终回答首字符必须是 `{`，末字符必须是 `}`。
- JSON 字符串内部如需引用用户原词，禁止直接写未转义英文双引号；请使用中文引号“”或转义为 `\"`。
- 必须包含 `required` 列表中的所有字段。
- 每个字段值必须匹配 schema 中的类型。
- 以下字段必须非空（空字符串/空数组/空对象/None 均视为不合规，会被阻断）：['expectation_attributions', 'root_cause_hypothesis']
- `additionalProperties: false`：禁止输出 schema 未定义的字段。
- 禁止把 schema 里的类型描述符（如 "string"）原样当作内容填进去——每个字段必须填入真实内容。

{
  "expectation_attributions": [
    {
      "expectation_id": "意图标签为 customer_portrait",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "stage: intent_api_call (可能返回了原始意图 other 或 None)",
        "stage: adapter_extraction (解析意图逻辑可能错误)",
        "stage: label_mapping (映射表 INTENT_MAPPING 将 raw_intent=None 映射为 other)"
      ],
      "root_cause_hypothesis": "API 调用未能正确识别用户意图为 customer_portrait，可能原始返回为 None 或其他低置信度标签，经由 adapter_extraction 与 label_mapping 逐步传递，最终输出 other。",
      "evidence": [
        {"runtime_checks": {"raw_intent": null, "actual_mapping": "other", "actual_intent": "other"}},
        {"actual_intent_output": {"intent": "other"}},
        {"reference_contract": {"intent": "customer_portrait"}}
      ]
    },
    {
      "expectation_id": "置信度达到预期阈值",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "stage: intent_api_call (模型预测置信度低)",
        "stage: adapter_extraction (可能未正确传递原始置信度)"
      ],
      "root_cause_hypothesis": "由于意图被识别为 other，模型整体置信度低（0.5），反映出模型对该输入的不确定性，也可能是 adapter_extraction 忽略了原始的高置信度标签。",
      "evidence": [
        {"actual_intent_output": {"confidence": 0.5}},
        {"runtime_checks": {"actual_confidence": 0.5}}
      ]
    },
    {
      "expectation_id": "关键实体 target_value 提取正确",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "stage: intent_api_call (API 响应中可能未包含 target_value 字段)",
        "stage: adapter_extraction (未实现 target_value 的抽取逻辑)"
      ],
      "root_cause_hypothesis": "意图识别链路未配置实体抽取，或因意图被归类为 other 时跳过实体抽取，导致缺失 target_value。",
      "evidence": [
        {"actual_intent_output": {"subIntent": "其他意图", "intent": "other"}},
        {"reference_contract": {"target_value": "重疾险"}},
        {"runtime_checks": {"missing_required_slots": []}}
      ]
    },
    {
      "expectation_id": "意图不属于回退类别 other",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "stage: intent_api_call",
        "stage: adapter_extraction",
        "stage: label_mapping"
      ],
      "root_cause_hypothesis": "因意图被识别为 other，违背了此期望。",
      "evidence": [
        {"actual_intent_output": {"intent": "other"}}
      ]
    },
    {
      "expectation_id": "intent_contract",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
        "整体意图识别链路"
      ],
      "root_cause_hypothesis": "由于意图输出与 reference 不符，且缺失实体与低置信度，导致 contract 判定失败。",
      "evidence": [
        {"judge_result": {"overall_fulfillment": {"status": "not_fulfilled"}}}
      ]
    }
  ],
  "suspected_locations": [
    "stage: intent_api_call (/api/v1/marketing-planning/intent-recognition)",
    "stage: adapter_extraction (解析逻辑可能不完整)",
    "stage: label_mapping (映射表 INTENT_MAPPING 配置)",
    "file: projects/marketting-planning-intent/intent.py:INTENT_MAPPING"
  ],
  "root_cause_hypothesis": "意图识别 API 在输入“帮我看看上季度买了重疾险的客户都是啥样的？”时未能给出 customer_portrait 的明确结果，很可能返回了原始意图为 None 或低置信度的 other，导致下游解析器提取出 other，并经由标签映射维持 other，且缺失 target_value 实体。置信度 0.5 远低于参考要求 0.9。根本原因可能在于 API 的 prompt 设计不足以处理该类客户画像查询，或训练数据/模型对 customer_portrait 意图覆盖不足。同时 adapter 与映射逻辑未能兜底，直接透传了低质量结果。",
  "evidence": [
    {
      "type": "runtime_checks",
      "detail": "runtime_checks 显示 raw_intent=None, actual_mapping=other, actual_intent=other, expected_intent=customer_portrait"
    },
    {
      "type": "actual_output",
      "detail": {"intent": "other", "confidence": 0.5, "subIntent": "其他意图"}
    },
    {
      "type": "reference_contract",
      "detail": {"intent": "customer_portrait", "target_value": "重疾险", "confidence": 0.95}
    },
    {
      "type": "missing_entities",
      "detail": "target_value 未在输出中出现"
    },
    {
      "type": "contract_probe",
      "detail": "intent_contract_probe 确认 intent_match=false, evidence_gap=['intent_evidence']"
    }
  ],
  "evidence_strength": "high"
}

